const HS_API = "https://rbwm-api.hsbc.com.hk/pws-hk-hase-mortgage-eapi-prod-proxy/v1/property";
const HS_HEADERS = {
  "Content-Type": "application/json",
  "Referer": "https://www.hangseng.com/zh-hk/e-valuation/address-search/",
  "Origin": "https://www.hangseng.com",
  "Accept": "application/json",
};

function hkDateStr(offsetDays = 0) {
  return new Date(Date.now() + 8 * 3600000 + offsetDays * 86400000).toISOString().slice(0, 10);
}

// In-memory cache (per Worker instance lifetime)
let hsBlockListCache = null;
const hsEstateCache = new Map();

async function hsKeywordSearch(estateName) {
  if (hsEstateCache.has(estateName)) return hsEstateCache.get(estateName);
  const res = await fetch(`${HS_API}/keywordsearch?keyword=${encodeURIComponent(estateName)}`, { headers: HS_HEADERS });
  if (!res.ok) return null;
  const data = await res.json();
  const match = Array.isArray(data) ? data[0] : null;
  if (match) hsEstateCache.set(estateName, match);
  return match;
}

async function hsBlockList() {
  if (hsBlockListCache) return hsBlockListCache;
  const res = await fetch(`${HS_API}/area2blockfulllist`, { headers: HS_HEADERS });
  if (!res.ok) return null;
  hsBlockListCache = await res.json();
  return hsBlockListCache;
}

async function findBlockCode(estateCode, blockNum) {
  const list = await hsBlockList();
  if (!list) return null;
  const isNumeric = /^\d+$/.test(blockNum);
  for (const area of list.areas || []) {
    for (const dist of area.districts || []) {
      for (const estate of dist.estates || []) {
        if (estate.estateCode === String(estateCode)) {
          const blocks = estate.blocks || [];
          const block = isNumeric
            ? blocks.find(b =>
                b.blockChinesename === `第${blockNum}座` ||
                b.blockChinesename?.includes(`第${blockNum}座`) ||
                b.blockName === `Block/Tower ${blockNum}`
              )
            : blocks.find(b => {
                const cn = b.blockChinesename || '';
                const en = b.blockName || '';
                // Exact match or stripped 座 suffix
                if (cn === blockNum || cn === blockNum + '座' || cn.replace(/座$/, '') === blockNum) return true;
                if (en === blockNum || en === blockNum + '座') return true;
                // Multi-phase format: "I期--B座" or "Phase I--Block/Tower B"
                const cnLast = cn.split('--').pop() || '';
                const enLast = en.split('--').pop() || '';
                if (cnLast === blockNum + '座' || cnLast.replace(/座$/, '') === blockNum) return true;
                if (enLast === `Block/Tower ${blockNum}` || enLast === blockNum) return true;
                return false;
              }) || (blocks.length === 1 ? blocks[0] : null);
          return block ? { blockCode: block.blockCode, carpark: block.coveredCarpark || "0" } : null;
        }
      }
    }
  }
  return null;
}

async function getHangSengValuation(estateName, blockNum, floorNum, flatLetter) {
  const estate = await hsKeywordSearch(estateName);
  if (!estate) return null;
  const blockInfo = await findBlockCode(estate.estateCode, blockNum);
  if (!blockInfo) return null;
  const body = {
    area: String(estate.areaCode),
    district: String(estate.districtCode),
    estate: String(estate.estateCode),
    block: String(blockInfo.blockCode),
    floor: String(floorNum),
    flat: String(flatLetter),
    carpark: 0,
    tcKnowledge: "on",
    openCarpark: 0,
  };
  const res = await fetch(`${HS_API}/valuation`, { method: "POST", headers: HS_HEADERS, body: JSON.stringify(body) });
  if (!res.ok) return null;
  const data = await res.json();
  const result = Array.isArray(data) ? data[0] : data;
  if (result?.errorCode || result?.fieldName) return null;
  return { price: result.price, saleableArea: result.saleableArea, valuationDate: result.valuationDate };
}

function json(status, data) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json", ...CORS },
  });
}

async function sha256(text) {
  const buf = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(text));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, "0")).join("");
}

// ── Rate limiting ────────────────────────────────────────────────────────────
// 數字參數係「全局」security 設定：settings 表 sec_* key，code 有 default。
// 特登唔擺入 per-account ⚙️ CONFIG_DEFS——否則攻擊者可以自己較大自己個上限。
// 要改：直接落 D1 改 settings，例如
//   INSERT INTO settings (key,value) VALUES ('sec_api_rpm','500')
//   ON CONFLICT(key) DO UPDATE SET value=excluded.value;
const SEC_DEFAULTS = {
  sec_api_rpm: 240,   // 已登入 API：每個帳戶(或 IP)每分鐘 request 上限
  sec_auth_rpm: 10,   // login/register：每個 IP 每分鐘試嘅次數上限
};
let _secCfgCache = { at: 0, vals: null };
async function getSecCfg(db) {
  const now = Date.now();
  if (_secCfgCache.vals && now - _secCfgCache.at < 60000) return _secCfgCache.vals;
  const vals = { ...SEC_DEFAULTS };
  try {
    const { results } = await db.prepare("SELECT key, value FROM settings WHERE key LIKE 'sec_%'").all();
    for (const r of results) {
      const n = Number(r.value);
      if (Number.isFinite(n) && n > 0 && r.key in SEC_DEFAULTS) vals[r.key] = n;
    }
  } catch (_) { /* settings 表未有都照用 default */ }
  _secCfgCache = { at: now, vals };
  return vals;
}

// In-memory fixed-window counter（per isolate）。isolate 回收會重置——擋高速
// 暴力/scraping 夠用；真正嘅帳戶鎖靠 login 嘅 failed_attempts（durable，喺 D1）。
const RATE_BUCKETS = new Map(); // key -> { windowStart, count }
function rateLimited(key, limit, windowMs = 60000) {
  const now = Date.now();
  let b = RATE_BUCKETS.get(key);
  if (!b || now - b.windowStart >= windowMs) {
    b = { windowStart: now, count: 0 };
    RATE_BUCKETS.set(key, b);
  }
  b.count++;
  if (RATE_BUCKETS.size > 5000) {
    for (const [k, v] of RATE_BUCKETS) {
      if (now - v.windowStart >= windowMs) RATE_BUCKETS.delete(k);
    }
  }
  return b.count > limit;
}

function randomToken() {
  const arr = new Uint8Array(32);
  crypto.getRandomValues(arr);
  return Array.from(arr).map(b => b.toString(16).padStart(2, "0")).join("");
}

function normalizeUnit(unit) {
  if (!unit) return unit;
  // Strip leading zeros from numeric units: "01室" -> "1室", "10室" unchanged
  return unit.replace(/^0+(\d+室)$/, '$1');
}

async function ensureAuthTables(db) {
  await db.prepare(`CREATE TABLE IF NOT EXISTS accounts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    expiry_date TEXT NOT NULL,
    failed_attempts INTEGER NOT NULL DEFAULT 0,
    locked_until TEXT,
    is_active INTEGER NOT NULL DEFAULT 1
  )`).run();
  // Backfill is_active for pre-existing tables (CREATE IF NOT EXISTS won't add it).
  try { await db.prepare("ALTER TABLE accounts ADD COLUMN is_active INTEGER NOT NULL DEFAULT 1").run(); } catch (_) {}
  await db.prepare(`CREATE TABLE IF NOT EXISTS sessions (
    token TEXT PRIMARY KEY,
    account_id INTEGER NOT NULL,
    created_at TEXT NOT NULL,
    expires_at TEXT NOT NULL
  )`).run();
  // Seed seanwong account if not exists
  const existing = await db.prepare("SELECT id FROM accounts WHERE username = 'seanwong'").first();
  if (!existing) {
    const hash = await sha256("123456");
    await db.prepare("INSERT INTO accounts (username, password_hash, expiry_date) VALUES ('seanwong', ?, '2099-12-31')")
      .bind(hash).run();
  }
}

async function authenticate(db, request) {
  const auth = request.headers.get("Authorization") || "";
  const token = auth.startsWith("Bearer ") ? auth.slice(7) : null;
  if (!token) return null;
  const now = new Date().toISOString();
  const session = await db.prepare(
    "SELECT s.*, a.username, a.expiry_date FROM sessions s JOIN accounts a ON a.id = s.account_id WHERE s.token = ? AND s.expires_at > ?"
  ).bind(token, now).first();
  if (!session) return null;
  if (session.expiry_date < now.slice(0, 10)) return null;
  return session;
}

// ── 多用戶個人化 ──────────────────────────────────────────────────────────
// account_estates:每個 account 自己嘅屋苑訂閱(最愛/排序/加入日)。estates
// 變返全局 scrape 目錄——佢嘅 is_favourite/sort_order 遷移後唔再讀寫。
// added_at 係數據可見起點:售價歷史/趨勢/成交列表/動態只顯示由呢日開始
// 嘅記錄;分析功能(相對市價/類近成交/雷達中位數)照用全部(用戶確認)。
// viewings/system_parameters 加 account_id;分析參數 settings key 由
// cfg_<key> 變 cfg_<aid>_<key>。一次性遷移(settings flag 守住):現有嘅
// 偏好/睇樓/備注/設定全部 map 去 seanwong,added_at 用 estates.first_seen
// (保留返佢而家見到嘅全部歷史)。
async function ensureMultiAccount(db) {
  await db.prepare(`CREATE TABLE IF NOT EXISTS account_estates (
    account_id INTEGER NOT NULL,
    estate_id INTEGER NOT NULL,
    is_favourite INTEGER NOT NULL DEFAULT 0,
    sort_order INTEGER NOT NULL DEFAULT 0,
    added_at TEXT NOT NULL DEFAULT (date('now','+8 hours')),
    PRIMARY KEY (account_id, estate_id)
  )`).run();
  try { await db.prepare("ALTER TABLE viewings ADD COLUMN account_id INTEGER").run(); } catch (_) {}
  try { await db.prepare("ALTER TABLE system_parameters ADD COLUMN account_id INTEGER").run(); } catch (_) {}
  // 每日 email 逐帳戶寄去自己嘅 email（註冊時經 OTP 驗證）
  try { await db.prepare("ALTER TABLE accounts ADD COLUMN email TEXT").run(); } catch (_) {}
  await db.prepare(`CREATE TABLE IF NOT EXISTS email_otps (
    email TEXT PRIMARY KEY,
    code TEXT NOT NULL,
    expires_at TEXT NOT NULL,
    attempts INTEGER NOT NULL DEFAULT 0
  )`).run();
  // 朋友屋企：per-account 記錄朋友住邊個單位，攞成交/估值/市價參考
  await db.prepare(`CREATE TABLE IF NOT EXISTS friend_homes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    account_id INTEGER NOT NULL,
    friend_name TEXT NOT NULL,
    estate_id INTEGER NOT NULL,
    block TEXT NOT NULL,
    floor TEXT NOT NULL,
    unit TEXT NOT NULL,
    size_net INTEGER,
    bedrooms INTEGER,
    created_at TEXT DEFAULT (datetime('now'))
  )`).run();
  // 過往成交/估值抓一次就存落 DB，之後 load 唔使再外抓（見 enrichFriendHome）。
  // past_txns NULL = 未抓過（顯示「抓取中」）；'[]' = 抓過但冇記錄。
  for (const col of ["past_txns TEXT", "est_url TEXT", "hs_price INTEGER", "hs_area REAL", "hs_date TEXT", "enriched_at TEXT"]) {
    try { await db.prepare(`ALTER TABLE friend_homes ADD COLUMN ${col}`).run(); } catch (_) {}
  }
  await db.prepare("CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT)").run();
  const done = await db.prepare("SELECT 1 FROM settings WHERE key = 'multi_account_migrated'").first();
  if (done) return;
  const sean = await db.prepare("SELECT id FROM accounts WHERE username = 'seanwong'").first();
  if (!sean) return;   // seed 未行,下個 request 再試
  const aid = sean.id;
  // added_at 用極早日期:seanwong 係遷移前嘅唯一用戶,「現有 data 全部
  // map 去佢」= 佢要繼續見到全部歷史(包括成交記錄 tab 嘅 2003 年舊成交),
  // 唔可以用 first_seen 截。之後新加嘅訂閱先用「今日」做 added_at。
  await db.prepare(`
    INSERT OR IGNORE INTO account_estates (account_id, estate_id, is_favourite, sort_order, added_at)
    SELECT ?, id, COALESCE(is_favourite, 0), COALESCE(sort_order, 0), '2000-01-01'
    FROM estates WHERE is_disabled = 0 OR is_disabled IS NULL
  `).bind(aid).run();
  await db.prepare("UPDATE viewings SET account_id = ? WHERE account_id IS NULL").bind(aid).run();
  await db.prepare("UPDATE system_parameters SET account_id = ? WHERE account_id IS NULL").bind(aid).run();
  // cfg_<key> → cfg_<aid>_<key>(逐條抄再刪,喺 JS 對返 CONFIG_DEFS 先郁,
  // 唔會誤搬第啲 settings row)
  const { results: cfgRows } = await db.prepare("SELECT key, value FROM settings WHERE key LIKE 'cfg_%'").all();
  for (const r of cfgRows) {
    const bare = r.key.slice(4);
    if (!CONFIG_DEFS.some((d) => d.key === bare)) continue;
    await db.prepare("INSERT INTO settings (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value")
      .bind(`cfg_${aid}_${bare}`, r.value).run();
    await db.prepare("DELETE FROM settings WHERE key = ?").bind(r.key).run();
  }
  await db.prepare("INSERT INTO settings (key, value) VALUES ('multi_account_migrated', '1') ON CONFLICT(key) DO UPDATE SET value = '1'").run();
}

